import styles from "./Post.module.css";
import avatar from "./avatar.jpg";

const Post = (props) => {
  return (
    <div className={styles.post}>
      <img src={avatar} />
      {props.message}
      <div>
        <span>LIKE</span>
      </div>
      <div>
        <span>DISLIKE</span>
      </div>
    </div>
  );
};

export default Post;
